/*
* Show request error
* by Helen Callisaya
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERRORS.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == null || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

/*
* Calc Get the user id of the request 
* by Helen Callisaya
*/
return this._user.id;

/*
* Calc Validate Attach Documents
* by Helen Callisaya
*/
let loopRequestLen = this.END_ENDORSEMENTS_DOCUMENTS.length;
var submitVariables = new Object();
submitVariables['END_SUBMIT_VALIDATE_NAME'] = "NO";
submitVariables['END_SUBMIT_MESSAGE'] = "YES";
for (let i = 0; i < loopRequestLen; i++) {
    //Check that the Name is not null or empty
    if (this.END_ENDORSEMENTS_DOCUMENTS[i]['END_ENDORSEMENT_ATTACHMENT_NAME'] === null || 
        this.END_ENDORSEMENTS_DOCUMENTS[i]['END_ENDORSEMENT_ATTACHMENT_NAME'] == "" || 
        this.END_ENDORSEMENTS_DOCUMENTS[i]['END_ENDORSEMENT_ATTACHMENT_NAME'] == undefined) {

        if (this.END_ENDORSEMENTS_DOCUMENTS[i]['END_ENDORSEMENT_UPLOAD_DOCUMENT'] === null) {
                //Valid if length is 1
                if (loopRequestLen == 1) {
                    submitVariables['END_SUBMIT_MESSAGE'] = 'YES';
                } else {
                    submitVariables['END_SUBMIT_MESSAGE'] = 'NO';
                }		
        } else { 
            submitVariables['END_SUBMIT_MESSAGE'] = 'NO';           
        }
    } else {
        //Check that the Document is not null
        if (this.END_ENDORSEMENTS_DOCUMENTS[i]['END_ENDORSEMENT_UPLOAD_DOCUMENT'] === null) {
           submitVariables['END_SUBMIT_MESSAGE'] = 'NO'; 
        } 
    }
}
if(this.YQP_SUBMIT_SAVE == 'SUBMIT' || this.YQP_SUBMIT_SAVE == 'REVIEW' || this.YQP_SUBMIT_SAVE == 'UPLOAD') {
	//Validate Email and Name
    submitVariables['END_SUBMIT_VALIDATE_NAME'] = "YES";
}
return submitVariables;

/*
* Calc Get the user fullname of the request 
* by Helen Callisaya
*/
return this._user.fullname;

/*
* Calc Get Url Document
* by Helen Callisaya
*/
let urlDocument = "END_DOWNLOAD_" + this.END_TYPE_ENDORSEMENT + "_DOCUMENT_URL";

return this[urlDocument];

/*
* Calc Get Name Document
* by Helen Callisaya
*/
let urlDocument = "END_DOWNLOAD_" + this.END_TYPE_ENDORSEMENT + "_DOCUMENT_URL_NAME_BUTTON";
return this[urlDocument];

